/**
 * feed.js
 * Security Feed Dashboard — Frontend Logic
 *
 * AI Report:
 *  - "Default Report" loads report.json (pre-generated by GitHub Actions at 05:00 PT)
 *  - "Run Custom Prompt" sends a request to trigger a GitHub Actions workflow_dispatch
 *    that runs scraper.py with a CUSTOM_PROMPT env var, then commits report.json
 *  - The Refresh button triggers the same daily workflow via workflow_dispatch
 *  - Rate-limit (2h) is enforced client-side via localStorage
 *
 * API key is stored in GitHub Secrets (ANTHROPIC_API_KEY).
 * It is consumed server-side (Python/GitHub Actions) and NEVER sent to the browser.
 *
 * Workflow dispatch requires a GitHub PAT stored in GitHub Secrets (GH_DISPATCH_TOKEN)
 * and exposed as a meta tag by your build/deploy step, OR you can hardcode the repo
 * details below (they are not secret — only the token is).
 */

// ─────────────────────────────────────────────────────────────────
// CONFIGURATION — update these for your repo
// ─────────────────────────────────────────────────────────────────
const GITHUB_OWNER = 'TinkerWithAll';
const GITHUB_REPO  = 'Web';
const WORKFLOW_FILE = 'daily_scrape.yml';   // the workflow that runs scraper.py

// This token is a GitHub Fine-Grained PAT with "Actions: write" scope.
// Store it as a GitHub Secret called GH_DISPATCH_TOKEN and inject it
// at build time (see README / daily_scrape.yml for how to do this safely).
// For a purely static site, this value is set by the build workflow into a
// generated config.js file — see the workflow comments for the pattern.
// DO NOT paste your real PAT here in the source code.
const GH_PAT = window.GH_DISPATCH_TOKEN || '';   // injected at build time

const RATE_LIMIT_MS = 2 * 60 * 60 * 1000; // 2 hours
const RATE_LIMIT_KEY = 'feed_last_trigger';
// ─────────────────────────────────────────────────────────────────

document.addEventListener('DOMContentLoaded', () => {

  // ── DOM refs ──────────────────────────────────────────────────
  const lastUpdatedEl  = document.getElementById('last-updated');
  const articleCountEl = document.getElementById('article-count');
  const feedCountEl    = document.getElementById('feed-count');
  const feedBody       = document.getElementById('feedBody');
  const searchInput    = document.getElementById('searchInput');
  const termInput      = document.getElementById('termInput');
  const termToggleBtn  = document.getElementById('termToggleBtn');
  const downloadBtn    = document.getElementById('downloadBtn');
  const downloadTermsBtn = document.getElementById('downloadTermsBtn');
  const downloadFeedsBtn = document.getElementById('downloadFeedsBtn');
  const downloadReportBtn = document.getElementById('downloadReportBtn');
  const feedCountLabel = document.getElementById('feedCountLabel');
  const noResults      = document.getElementById('noResults');
  const refreshBtn     = document.getElementById('refreshBtn');
  const refreshBtnLabel= document.getElementById('refreshBtnLabel');
  const defaultReportBtn = document.getElementById('defaultReportBtn');
  const customReportBtn  = document.getElementById('customReportBtn');
  const customPrompt     = document.getElementById('customPrompt');
  const reportPlaceholder = document.getElementById('reportPlaceholder');
  const reportLoading     = document.getElementById('reportLoading');
  const reportContent     = document.getElementById('reportContent');
  const loadingMsg        = document.getElementById('loadingMsg');

  // ── State ─────────────────────────────────────────────────────
  let feedData = [];
  let searchModeIsAND = true;
  let currentReportData = null;   // stores last loaded report for download
  const cb = `?v=${Date.now()}`;

  // ── Eastern Time formatter ─────────────────────────────────────
  function toEastern(isoString) {
    try {
      const d = new Date(isoString);
      return d.toLocaleString('en-CA', {
        timeZone: 'America/Toronto',
        year: 'numeric', month: '2-digit', day: '2-digit',
        hour: '2-digit', minute: '2-digit', hour12: false
      }) + ' ET';
    } catch { return isoString; }
  }

  // ── TABS ──────────────────────────────────────────────────────
  document.querySelectorAll('.tab-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
      document.querySelectorAll('.tab-panel').forEach(p => p.classList.remove('active'));
      btn.classList.add('active');
      document.getElementById(`tab-${btn.dataset.tab}`).classList.add('active');
    });
  });

  // ── Metadata ──────────────────────────────────────────────────
  fetch(`meta.json${cb}`)
    .then(r => r.json())
    .then(d => {
      if (lastUpdatedEl && d.last_updated) {
        // meta.json stores Eastern time already; display as-is
        lastUpdatedEl.textContent = d.last_updated;
      }
    })
    .catch(() => {});

  // ── Exact feed count from feeds.txt ───────────────────────────
  fetch(`feeds.txt${cb}`)
    .then(r => r.text())
    .then(text => {
      const count = text.split('\n').filter(l => l.trim().startsWith('http')).length;
      if (feedCountEl) feedCountEl.textContent = count;
    })
    .catch(() => { if (feedCountEl) feedCountEl.textContent = '180'; });

  // ── AI enabled check ──────────────────────────────────────────
  // Read report.json on load to check whether AI is currently enabled.
  // If ai_enabled === false, disable buttons and show a notice.
  fetch(`report.json${cb}`)
    .then(r => r.ok ? r.json() : null)
    .then(data => {
      if (data && data.ai_enabled === false) {
        disableAI(data.message || 'AI analysis is currently disabled by the administrator.');
      }
    })
    .catch(() => {});   // no report.json yet — leave buttons active

  function disableAI(msg) {
    defaultReportBtn.disabled = true;
    customReportBtn.disabled  = true;
    customPrompt.disabled     = true;
    customPrompt.placeholder  = 'AI features are currently disabled.';
    reportPlaceholder.innerHTML = `
      <div class="ph-icon" style="color:var(--amber)">
        <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1">
          <circle cx="12" cy="12" r="10"></circle>
          <line x1="12" y1="8" x2="12" y2="12"></line>
          <line x1="12" y1="16" x2="12.01" y2="16"></line>
        </svg>
      </div>
      <p style="color:var(--amber)">${escHtml(msg)}</p>
      <p class="ph-sub">To re-enable: set the <code>AI_ENABLED</code> Actions Variable to <code>true</code>,
      or set <code>AI_REPORTS_ENABLED_CODE = True</code> in scraper.py.</p>`;
  }

  // ── Feed data ─────────────────────────────────────────────────
  fetch('feed_history.json')
    .then(r => { if (!r.ok) throw new Error(); return r.json(); })
    .then(data => {
      feedData = data;
      if (articleCountEl) articleCountEl.textContent = data.length;
      renderTable(data);
    })
    .catch(() => {
      feedBody.innerHTML = `<tr><td colspan="3" style="text-align:center;color:var(--text-faint);padding:2rem">No data available.</td></tr>`;
    });

  // ── Render Table ──────────────────────────────────────────────
  function renderTable(data) {
    feedBody.innerHTML = '';
    noResults.style.display = data.length === 0 ? 'block' : 'none';
    feedCountLabel.textContent = `${data.length} article${data.length !== 1 ? 's' : ''}`;

    data.forEach(item => {
      const tr = document.createElement('tr');
      const tagsHtml = (item.terms || [])
        .map(t => `<span class="term-tag">${escHtml(t)}</span>`).join('');
      tr.innerHTML = `
        <td class="mono" style="color:var(--text-dim);font-size:11px">${escHtml(item.date)}</td>
        <td><a href="${escHtml(item.link)}" target="_blank" rel="noopener noreferrer">${escHtml(item.title)}</a></td>
        <td>${tagsHtml}</td>`;
      feedBody.appendChild(tr);
    });
  }

  // ── Filter ────────────────────────────────────────────────────
  function filterData() {
    const txt = searchInput.value.toLowerCase();
    const terms = termInput.value.toLowerCase().split(',')
      .map(t => t.trim()).filter(Boolean);

    const filtered = feedData.filter(item => {
      const textOk = !txt || item.title.toLowerCase().includes(txt);
      if (terms.length === 0) return textOk;
      const articleTerms = (item.terms || []).map(t => t.toLowerCase());
      const termOk = searchModeIsAND
        ? terms.every(st => articleTerms.some(at => at.includes(st)))
        : terms.some(st => articleTerms.some(at => at.includes(st)));
      return textOk && termOk;
    });

    renderTable(filtered);
    return filtered;
  }

  searchInput.addEventListener('input', filterData);
  termInput.addEventListener('input', filterData);

  termToggleBtn.addEventListener('click', () => {
    searchModeIsAND = !searchModeIsAND;
    termToggleBtn.textContent = searchModeIsAND ? 'AND' : 'OR';
    termToggleBtn.className = searchModeIsAND ? 'toggle-and' : 'toggle-or';
    filterData();
  });

  // ── Export CSV ────────────────────────────────────────────────
  downloadBtn.addEventListener('click', () => {
    const current = filterData();
    if (!current.length) return alert('No data to export.');
    const rows = [['Date', 'Title', 'Link', 'Terms']];
    current.forEach(i => rows.push([
      i.date,
      `"${(i.title || '').replace(/"/g, '""')}"`,
      i.link,
      `"${(i.terms || []).join(', ')}"`,
    ]));
    const blob = new Blob([rows.map(r => r.join(',')).join('\n')], { type: 'text/csv' });
    triggerDownload(URL.createObjectURL(blob), `security_feed_${iso()}.csv`);
  });

  // ── Download Report as HTML ───────────────────────────────────
  if (downloadReportBtn) {
    downloadReportBtn.addEventListener('click', () => {
      if (!currentReportData) return;
      const ts = currentReportData.generated_at ? toEastern(currentReportData.generated_at) : 'unknown';
      const content = reportContent.innerHTML;
      const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Security Intel Report — ${ts}</title>
<style>
  body { font-family: 'Courier New', monospace; background: #0a0c0f; color: #e8f0f8; padding: 2rem; max-width: 900px; margin: 0 auto; font-size: 14px; line-height: 1.7; }
  a { color: #00e5a0; }
  .report-meta { color: #8fa8c0; margin-bottom: 2rem; padding-bottom: 1rem; border-bottom: 1px solid #1e2530; }
  .report-ts { color: #00e5a0; }
  .report-badge { background: #151a22; border: 1px solid #2a3545; padding: 2px 8px; border-radius: 3px; font-size: 11px; text-transform: uppercase; }
  .r-section { margin-bottom: 2rem; }
  .r-section-title { color: #00e5a0; font-size: 1rem; font-weight: bold; margin-bottom: 1rem; padding-bottom: 0.3rem; border-bottom: 1px solid #1e2530; }
  .cve-card, .ta-card, .canada-card, .source-item { background: #151a22; border: 1px solid #1e2530; border-radius: 6px; padding: 1rem; margin-bottom: 0.75rem; }
  .cve-card { border-left: 3px solid #ff4757; }
  .cve-card.high { border-left-color: #ffb830; }
  .cve-card.med { border-left-color: #4fa3e3; }
  .cve-id { color: #ffb830; font-weight: bold; }
  .ta-card { border-left: 3px solid #ffb830; }
  .ta-name { color: #ffb830; font-weight: bold; margin-bottom: 0.5rem; }
  .crit-badge { font-size: 11px; padding: 2px 6px; border-radius: 3px; }
  .crit-badge.CRITICAL { color: #ff4757; }
  .crit-badge.HIGH { color: #ffb830; }
  .crit-badge.MEDIUM { color: #4fa3e3; }
  .term-tag { background: rgba(0,229,160,0.1); color: #00a872; border: 1px solid rgba(0,229,160,0.2); padding: 1px 6px; border-radius: 10px; font-size: 11px; margin: 2px; display: inline-block; }
  .source-date { color: #8fa8c0; margin-right: 1rem; }
  .source-link { color: #e8f0f8; }
  .sources-list .source-item { padding: 0.5rem 0.75rem; }
  strong { color: #e8f0f8; }
</style>
</head>
<body>${content}</body>
</html>`;
      const blob = new Blob([html], { type: 'text/html' });
      triggerDownload(URL.createObjectURL(blob), `security-report-${iso()}.html`);
    });
  }

  // ── Download txt files ────────────────────────────────────────
  function downloadTxt(filename) {
    fetch(filename)
      .then(r => { if (!r.ok) throw new Error(); return r.text(); })
      .then(text => {
        const blob = new Blob([text], { type: 'text/plain' });
        triggerDownload(URL.createObjectURL(blob), filename);
      })
      .catch(() => alert(`Could not download ${filename}`));
  }
  downloadTermsBtn.addEventListener('click', () => downloadTxt('terms.txt'));
  downloadFeedsBtn.addEventListener('click', () => downloadTxt('feeds.txt'));

  // ── Refresh Button ────────────────────────────────────────────
  function getRemainingCooldown() {
    const last = parseInt(localStorage.getItem(RATE_LIMIT_KEY) || '0', 10);
    return Math.max(0, RATE_LIMIT_MS - (Date.now() - last));
  }

  function updateRefreshBtn() {
    const rem = getRemainingCooldown();
    if (rem > 0) {
      const mins = Math.ceil(rem / 60000);
      refreshBtn.disabled = true;
      refreshBtnLabel.textContent = `Cooldown ${mins}m`;
    } else {
      refreshBtn.disabled = false;
      refreshBtnLabel.textContent = 'Refresh';
    }
  }

  updateRefreshBtn();
  setInterval(updateRefreshBtn, 30000);

  refreshBtn.addEventListener('click', async () => {
    if (getRemainingCooldown() > 0) return;
    if (!GH_PAT) {
      alert('GitHub dispatch token not configured. See feed.js comments and your workflow setup.');
      return;
    }
    refreshBtn.disabled = true;
    refreshBtnLabel.textContent = 'Triggering…';
    const ok = await triggerWorkflow({});
    if (ok) {
      localStorage.setItem(RATE_LIMIT_KEY, Date.now().toString());
      refreshBtnLabel.textContent = 'Triggered ✓';
      setTimeout(updateRefreshBtn, 3000);
    } else {
      refreshBtnLabel.textContent = 'Error';
      setTimeout(updateRefreshBtn, 3000);
    }
  });

  // ── AI Report ─────────────────────────────────────────────────
  function showLoading(msg) {
    reportPlaceholder.style.display = 'none';
    reportContent.style.display = 'none';
    reportLoading.style.display = 'flex';
    loadingMsg.textContent = msg || 'Generating intelligence briefing…';
  }
  function hideLoading() { reportLoading.style.display = 'none'; }

  // Default report: just loads report.json committed by GitHub Actions
  defaultReportBtn.addEventListener('click', async () => {
    defaultReportBtn.disabled = true;
    customReportBtn.disabled = true;
    showLoading('Loading cached intelligence report…');
    try {
      const r = await fetch(`report.json${cb}`);
      if (!r.ok) throw new Error('report.json not found');
      const data = await r.json();
      renderReport(data, false);
    } catch (e) {
      showError('report.json not found. Make sure your GitHub Action has run at least once and committed the report.');
    } finally {
      defaultReportBtn.disabled = false;
      customReportBtn.disabled = false;
    }
  });

  // Custom prompt: triggers workflow with custom prompt, then polls for updated report
  customReportBtn.addEventListener('click', async () => {
    const prompt = customPrompt.value.trim();
    if (!prompt) { customPrompt.focus(); return; }
    if (!GH_PAT) {
      alert('GitHub dispatch token not configured. See feed.js comments.');
      return;
    }
    customReportBtn.disabled = true;
    defaultReportBtn.disabled = true;
    showLoading('Dispatching custom analysis… this may take 1–2 minutes.');
    const ok = await triggerWorkflow({ custom_prompt: prompt });
    if (!ok) {
      showError('Failed to trigger workflow. Check GH_DISPATCH_TOKEN configuration.');
      customReportBtn.disabled = false;
      defaultReportBtn.disabled = false;
      return;
    }
    // Poll for updated report.json (workflow takes ~60-90s to complete)
    loadingMsg.textContent = 'Running analysis… polling for results (up to 3 min)…';
    const result = await pollForReport(180);
    hideLoading();
    if (result) {
      renderReport(result, true, prompt);
    } else {
      showError('Timed out waiting for report. Check GitHub Actions for errors, then try Default Report.');
    }
    customReportBtn.disabled = false;
    defaultReportBtn.disabled = false;
  });

  async function triggerWorkflow(inputs) {
    try {
      const res = await fetch(
        `https://api.github.com/repos/${GITHUB_OWNER}/${GITHUB_REPO}/actions/workflows/${WORKFLOW_FILE}/dispatches`,
        {
          method: 'POST',
          headers: {
            'Authorization': `Bearer ${GH_PAT}`,
            'Accept': 'application/vnd.github+json',
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({ ref: 'main', inputs }),
        }
      );
      return res.status === 204;
    } catch { return false; }
  }

  async function pollForReport(timeoutSecs) {
    // Record current report timestamp so we detect a new one
    let oldTs = null;
    try {
      const r = await fetch(`report.json${cb}`);
      if (r.ok) { const d = await r.json(); oldTs = d.generated_at; }
    } catch {}

    const deadline = Date.now() + timeoutSecs * 1000;
    while (Date.now() < deadline) {
      await sleep(8000);
      try {
        const r = await fetch(`report.json?v=${Date.now()}`);
        if (r.ok) {
          const d = await r.json();
          if (d.generated_at && d.generated_at !== oldTs) return d;
        }
      } catch {}
    }
    return null;
  }

  function renderReport(data, isCustom, prompt) {
    hideLoading();
    reportPlaceholder.style.display = 'none';
    reportContent.style.display = 'block';
    currentReportData = data;
    if (downloadReportBtn) downloadReportBtn.style.display = 'flex';

    const ts = data.generated_at ? toEastern(data.generated_at) : '—';
    const badge = isCustom
      ? `<span class="report-badge custom">Custom</span>`
      : `<span class="report-badge">48h Brief</span>`;

    let html = `
      <div class="report-meta">
        ${badge}
        <span>Generated: <span class="report-ts mono">${escHtml(ts)}</span></span>
        ${isCustom && prompt ? `<span style="color:var(--text-dim);font-size:13px">Prompt: "${escHtml(prompt.substring(0,80))}${prompt.length>80?'…':''}"</span>` : ''}
      </div>`;

    if (data.custom_response) {
      html += `<div class="r-section"><div class="canada-card">${markdownToHtml(data.custom_response)}</div></div>`;
    } else {
      html += renderVulnSection(data.vulnerabilities);
      html += renderTASection(data.threat_actors);
      html += renderCanadaSection(data.canada_landscape);
    }

    // Source articles section — links to original articles that fed the report
    html += renderSourcesSection();

    reportContent.innerHTML = html;
  }

  function renderSourcesSection() {
    // Pull the most recent 48h articles from feedData as source references
    if (!feedData.length) return '';
    const cutoff = new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString().slice(0,10);
    const recent = feedData.filter(i => i.date >= cutoff).slice(0, 50);
    if (!recent.length) return '';

    let html = `
      <div class="r-section">
        <div class="r-section-title">
          Source Articles
          <span class="r-section-count">${recent.length} articles</span>
        </div>
        <div class="sources-list">`;
    recent.forEach(item => {
      const tags = (item.terms || []).slice(0,3).map(t => `<span class="term-tag">${escHtml(t)}</span>`).join('');
      html += `
        <div class="source-item">
          <span class="source-date mono">${escHtml(item.date)}</span>
          <a href="${escHtml(item.link)}" target="_blank" rel="noopener noreferrer" class="source-link">${escHtml(item.title)}</a>
          <div class="source-tags">${tags}</div>
        </div>`;
    });
    html += `</div></div>`;
    return html;
  }

  function renderVulnSection(vulns) {
    if (!vulns) return '';
    const items = vulns.items || [];
    let html = `
      <div class="r-section">
        <div class="r-section-title">
          New Vulnerabilities
          <span class="r-section-count">${vulns.count ?? items.length} CVEs</span>
        </div>
        <div class="cve-list">`;

    if (!items.length) {
      html += `<p class="r-empty">No new CVEs matched in the last 48h.</p>`;
    } else {
      items.forEach(cve => {
        const cls = critClass(cve.criticality);
        html += `
          <div class="cve-card ${cls}">
            <div class="cve-header">
              <span class="cve-id">${escHtml(cve.id || '')}</span>
              <span class="cve-title">${escHtml(cve.description || '')}</span>
              <span class="crit-badge ${escHtml(cve.criticality || 'UNKNOWN')}">${escHtml(cve.criticality || '?')}</span>
            </div>
            <div class="cve-meta">
              <div class="cve-meta-item"><strong>Software:</strong> ${escHtml(cve.software_affected || '—')}</div>
              <div class="cve-meta-item"><strong>CIA Impact:</strong> ${escHtml(cve.cia_impact || '—')}</div>
              <div class="cve-meta-item"><strong>Access Required:</strong> ${escHtml(cve.access_required || '—')}</div>
            </div>
          </div>`;
      });
    }
    html += `</div></div>`;
    return html;
  }

  function renderTASection(actors) {
    if (!actors) return '';
    const items = actors.items || [];
    let html = `
      <div class="r-section">
        <div class="r-section-title">
          Active Threat Actors
          <span class="r-section-count">${items.length} active</span>
        </div>
        <div class="ta-list">`;

    if (!items.length) {
      html += `<p class="r-empty">No threat actor activity matched in the last 48h.</p>`;
    } else {
      items.forEach(ta => {
        html += `
          <div class="ta-card">
            <div class="ta-name">${escHtml(ta.name || '')}</div>
            <div class="ta-body">
              ${ta.targets ? `<p><strong>Targets / Breaches:</strong> ${escHtml(ta.targets)}</p>` : ''}
              ${ta.ttps    ? `<p><strong>TTPs to Watch:</strong> ${escHtml(ta.ttps)}</p>` : ''}
              ${ta.iocs && ta.iocs.length ? `
                <p><strong>New IoCs:</strong></p>
                <div class="ioc-tags">${ta.iocs.map(i => `<span class="ioc-tag">${escHtml(i)}</span>`).join('')}</div>` : ''}
            </div>
          </div>`;
      });
    }
    html += `</div></div>`;
    return html;
  }

  function renderCanadaSection(canada) {
    if (!canada) return '';
    let html = `
      <div class="r-section">
        <div class="r-section-title">Canadian Cyber Landscape</div>
        <div class="canada-card">`;
    if (canada.summary) html += `<p>${escHtml(canada.summary)}</p>`;
    if (canada.retailers)   html += `<p><strong><span class="ca-flag">🇨🇦</span>Retailers:</strong> ${escHtml(canada.retailers)}</p>`;
    if (canada.financial)   html += `<p><strong><span class="ca-flag">🇨🇦</span>Financial:</strong> ${escHtml(canada.financial)}</p>`;
    if (!canada.summary && !canada.retailers && !canada.financial) {
      html += `<p class="r-empty">No Canadian-specific incidents matched in the last 48h.</p>`;
    }
    html += `</div></div>`;
    return html;
  }

  function showError(msg) {
    hideLoading();
    reportPlaceholder.style.display = 'none';
    reportContent.style.display = 'block';
    reportContent.innerHTML = `
      <div style="padding:2rem;color:var(--red);font-size:12px;line-height:1.7">
        <strong>Error:</strong> ${escHtml(msg)}
      </div>`;
  }

  // ── Helpers ───────────────────────────────────────────────────
  function escHtml(s) {
    return String(s ?? '')
      .replace(/&/g,'&amp;').replace(/</g,'&lt;')
      .replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }

  function critClass(c) {
    const m = { CRITICAL:'crit', HIGH:'high', MEDIUM:'med', LOW:'low' };
    return m[(c||'').toUpperCase()] || 'med';
  }

  function iso() { return new Date().toISOString().slice(0,10); }

  function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

  function triggerDownload(url, filename) {
    const a = document.createElement('a');
    a.href = url; a.download = filename; a.click();
    URL.revokeObjectURL(url);
  }

  // Very lightweight markdown → HTML (for custom responses)
  function markdownToHtml(md) {
    return md
      .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
      .replace(/^### (.+)$/gm, '<h4 style="color:var(--green);margin:1rem 0 0.4rem;font-size:0.85rem;letter-spacing:0.05em">$1</h4>')
      .replace(/^## (.+)$/gm,  '<h3 style="color:var(--amber);margin:1.2rem 0 0.5rem;font-size:0.95rem">$1</h3>')
      .replace(/^# (.+)$/gm,   '<h2 style="color:var(--green);margin:1.5rem 0 0.5rem;font-size:1.1rem">$1</h2>')
      .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
      .replace(/`([^`]+)`/g, '<code style="color:var(--amber);font-size:11px">$1</code>')
      .replace(/^- (.+)$/gm, '<li style="margin-left:1.2rem;margin-bottom:0.2rem">$1</li>')
      .replace(/\n\n/g, '<br><br>')
      .replace(/\n/g, '<br>');
  }

});
